const SLIDES: string[] = [
  "<section data-label=\"الغلاف\" data-screen-label=\"01\" data-speaker-notes=\"افتتاحية دافئة: مرحبًا، سأشرح لك سند تمامًا كما سأشرح لك مقرّرك. اجلس واستمع، وسنبدأ الدرس الأول.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:radial-gradient(120% 130% at 88% 0%,#27326B,#1E2553 55%,#161D44);color:#fff;padding:96px 110px;display:flex;align-items:center;gap:72px;position:relative;overflow:hidden;\">\n  <div style=\"position:absolute;top:-140px;right:-120px;width:520px;height:520px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,92,.28),transparent 68%);filter:blur(6px);\"></div>\n  <div style=\"position:absolute;bottom:-180px;left:-120px;width:560px;height:560px;border-radius:50%;background:radial-gradient(circle,rgba(76,87,199,.34),transparent 68%);\"></div>\n  <div style=\"flex:1.15;display:flex;flex-direction:column;gap:30px;position:relative;z-index:1;\">\n    <div style=\"display:flex;align-items:center;gap:14px;\">\n      <span style=\"width:26px;height:26px;background:#FF6B5C;border-radius:50%;\"></span>\n      <span style=\"font:700 26px 'Noto Sans';letter-spacing:.08em;\">SANAD</span>\n      <span style=\"font:600 24px 'Noto Sans Arabic';color:#A8AEE0;margin-right:8px;\">دورة تعريفية</span>\n    </div>\n    <div style=\"display:inline-flex;align-self:flex-start;align-items:center;gap:10px;background:rgba(255,255,255,.08);border:1px solid rgba(168,174,224,.28);border-radius:999px;padding:9px 20px;font:600 22px 'Noto Sans Arabic';color:#D7DAF2;\">\n      <span style=\"width:9px;height:9px;border-radius:50%;background:#FF6B5C;\"></span>الدرس الأول · ٦ دقائق\n    </div>\n    <h1 style=\"font:700 132px/.98 'Noto Sans Arabic';letter-spacing:-.01em;margin:0;\">تعرّف على سند<span style=\"color:#FF6B5C;\">.</span></h1>\n    <p style=\"font:500 40px/1.4 'Noto Sans Arabic';color:#D7DAF2;margin:0;max-width:820px;\">مدرّسك الخصوصي الذكي — يشرح، ويسأل، ويتابع تقدّمك.</p>\n    <div style=\"width:130px;height:6px;background:#FF6B5C;border-radius:3px;\"></div>\n    <p style=\"font:400 27px/1.55 'Noto Sans Arabic';color:#A8AEE0;margin:0;max-width:760px;\">اجلس واستمع… سأشرح لك <span style=\"color:#fff;\">سند نفسه</span> تمامًا كما سأشرح لك أي مقرّر دراسي.</p>\n  </div>\n  <div style=\"flex:1;display:flex;justify-content:center;align-items:center;position:relative;z-index:1;\">\n    <div style=\"display:flex;flex-direction:column;align-items:center;\">\n      <span style=\"font:700 130px/1 'Bricolage Grotesque',sans-serif;color:#fff;letter-spacing:-.03em;\">sanad</span>\n      <span style=\"width:240px;height:15px;border-radius:8px;background:#FF6B5C;margin-top:28px;\"></span>\n    </div>\n  </div>\n</section>",
  "<section data-label=\"كيف يشرح سند\" data-screen-label=\"مثال\" data-speaker-notes=\"هذا مثال حيّ: بدل أن أصف لك سند، دعني أُريك. هذه شريحة محاضرة جامعية حقيقية عن التشفير بالمفتاح العام، وسأشرحها لك تمامًا كما سيشرحها سند لأي طالب — يعرض المحتوى، يُبرز الفكرة الأساسية، ويربط الأمثلة بالمبدأ.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:64px 90px 52px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;align-items:center;justify-content:space-between;margin-bottom:26px;\">\n    <div style=\"display:flex;align-items:center;gap:16px;\">\n      <span style=\"display:inline-flex;align-items:center;gap:10px;background:#FF6B5C;color:#fff;border-radius:999px;padding:10px 22px;font:700 24px 'Noto Sans Arabic';\"><span style=\"width:9px;height:9px;border-radius:50%;background:#fff;\"></span>كيف يشرح سند</span>\n      <span style=\"font:500 26px 'Noto Sans Arabic';color:#5A5F7A;\">بدل أن نصفه — إليك شريحة محاضرة حقيقية، كما يعرضها سند ويشرحها.</span>\n    </div>\n    <span style=\"font:600 22px 'Noto Sans Arabic';color:#8B8FA8;\">مثال حيّ · أمن المعلومات</span>\n  </div>\n\n  <!-- the displayed lecture slide -->\n  <div style=\"flex:1;border-radius:26px;background:#0e1430;padding:16px;box-shadow:0 36px 80px rgba(14,20,48,.32),inset 0 0 0 2px rgba(255,255,255,.05);display:flex;flex-direction:column;\">\n    <div style=\"flex:1;border-radius:16px;background:#fff;display:flex;flex-direction:column;overflow:hidden;\">\n      <!-- slide header bar -->\n      <div dir=\"ltr\" style=\"display:flex;align-items:center;justify-content:space-between;padding:16px 32px;background:#F4EFE6;border-bottom:1px solid #E7E1D6;\">\n        <span style=\"font:600 20px 'Noto Sans';color:#5A5F7A;\">Information Security · Lecture 7</span>\n        <span style=\"font:600 20px 'Noto Sans';color:#8B8FA8;\">Public-Key Cryptography</span>\n      </div>\n      <!-- slide content (LTR academic) -->\n      <div dir=\"ltr\" style=\"flex:1;padding:34px 44px 30px;display:flex;flex-direction:column;gap:22px;\">\n        <h2 style=\"font:700 46px/1.1 'Noto Sans';margin:0;color:#1E2553;\">Public-Key Cryptography <span style=\"color:#8B8FA8;font-weight:600;font-size:30px;\">(Asymmetric Encryption)</span></h2>\n        <div style=\"flex:1;display:grid;grid-template-columns:1fr 1.12fr;gap:40px;\">\n          <!-- LEFT: problem + key idea -->\n          <div style=\"display:flex;flex-direction:column;gap:22px;\">\n            <div>\n              <div style=\"font:700 26px 'Noto Sans';color:#E8503F;margin-bottom:8px;\">The Problem</div>\n              <p style=\"font:400 24px/1.5 'Noto Sans';color:#3A3F5A;margin:0;\">Symmetric encryption needs a <b style=\"color:#1E2553;\">shared secret key</b>. But how can two people who have never met agree on a secret — over an open, insecure channel?</p>\n            </div>\n            <div style=\"height:1px;background:#F0EBE1;\"></div>\n            <div>\n              <div style=\"font:700 26px 'Noto Sans';color:#E8503F;margin-bottom:14px;\">The Key Idea — a Key Pair</div>\n              <div style=\"display:flex;flex-direction:column;gap:12px;\">\n                <div style=\"display:flex;align-items:center;gap:16px;background:#FBF7F1;border:1.5px solid #E7E1D6;border-radius:14px;padding:16px 20px;\">\n                  <span style=\"font-size:28px;\">🔓</span>\n                  <div><div style=\"font:700 24px 'Noto Sans';color:#1E2553;\">Public Key</div><div style=\"font:400 20px 'Noto Sans';color:#5A5F7A;\">published openly — shared with anyone</div></div>\n                </div>\n                <div style=\"display:flex;align-items:center;gap:16px;background:#FBF7F1;border:1.5px solid #E7E1D6;border-radius:14px;padding:16px 20px;\">\n                  <span style=\"font-size:28px;\">🔑</span>\n                  <div><div style=\"font:700 24px 'Noto Sans';color:#1E2553;\">Private Key</div><div style=\"font:400 20px 'Noto Sans';color:#5A5F7A;\">kept secret — never shared</div></div>\n                </div>\n              </div>\n              <div style=\"margin-top:14px;display:flex;align-items:center;gap:12px;background:#FFE3DE;border-radius:12px;padding:14px 18px;box-shadow:0 0 0 2px #FF6B5C;\">\n                <span style=\"font:600 19px 'Noto Sans Arabic';color:#E8503F;white-space:nowrap;\">✦ لاحظ هذه النقطة</span>\n                <span style=\"font:700 22px/1.35 'Noto Sans';color:#1E2553;\">What one key locks, only the other can unlock.</span>\n              </div>\n            </div>\n          </div>\n          <!-- RIGHT: how it works + why secure -->\n          <div style=\"display:flex;flex-direction:column;gap:20px;\">\n            <div>\n              <div style=\"font:700 26px 'Noto Sans';color:#E8503F;margin-bottom:14px;\">How It Works</div>\n              <div style=\"display:flex;flex-direction:column;gap:10px;\">\n                <div style=\"display:flex;align-items:center;gap:16px;\"><span style=\"flex:none;width:36px;height:36px;border-radius:10px;background:#1E2553;color:#fff;display:flex;align-items:center;justify-content:center;font:700 20px 'Noto Sans';\">1</span><span style=\"font:500 22px 'Noto Sans';color:#3A3F5A;\"><b style=\"color:#1E2553;\">Alice</b> publishes her Public Key.</span></div>\n                <div style=\"display:flex;align-items:center;gap:16px;\"><span style=\"flex:none;width:36px;height:36px;border-radius:10px;background:#1E2553;color:#fff;display:flex;align-items:center;justify-content:center;font:700 20px 'Noto Sans';\">2</span><span style=\"font:500 22px 'Noto Sans';color:#3A3F5A;\"><b style=\"color:#1E2553;\">Bob</b> encrypts with Alice's Public Key.</span></div>\n                <div style=\"display:flex;align-items:center;gap:16px;\"><span style=\"flex:none;width:36px;height:36px;border-radius:10px;background:#FF6B5C;color:#fff;display:flex;align-items:center;justify-content:center;font:700 20px 'Noto Sans';\">3</span><span style=\"font:500 22px 'Noto Sans';color:#3A3F5A;\">Only Alice's <b style=\"color:#1E2553;\">Private Key</b> can decrypt it.</span></div>\n              </div>\n              <div style=\"margin-top:12px;display:flex;align-items:center;gap:12px;background:#F4EFE6;border-radius:12px;padding:13px 18px;\">\n                <svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#8B8FA8\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7-10-7-10-7Z\"></path><circle cx=\"12\" cy=\"12\" r=\"3\"></circle></svg>\n                <span style=\"font:400 20px/1.4 'Noto Sans';color:#5A5F7A;\">An eavesdropper sees the public key + the ciphertext — and still <b style=\"color:#1E2553;\">cannot read the message</b>.</span>\n              </div>\n            </div>\n            <div style=\"height:1px;background:#F0EBE1;\"></div>\n            <div>\n              <div style=\"font:700 26px 'Noto Sans';color:#E8503F;margin-bottom:8px;\">Why It's Secure</div>\n              <p style=\"font:400 22px/1.5 'Noto Sans';color:#3A3F5A;margin:0;\">Built on <b style=\"color:#1E2553;\">one-way (trapdoor) functions</b>: easy forward, infeasible to reverse — multiplying two large primes is easy; factoring the result is practically impossible → <b style=\"color:#1E2553;\">RSA</b>.</p>\n              <div style=\"display:flex;align-items:center;gap:10px;margin-top:14px;\">\n                <span style=\"font:600 20px 'Noto Sans';color:#1E2553;background:#EEF0FA;border-radius:999px;padding:8px 18px;\">RSA</span>\n                <span style=\"font:600 20px 'Noto Sans';color:#1E2553;background:#EEF0FA;border-radius:999px;padding:8px 18px;\">Diffie–Hellman</span>\n                <span style=\"font:600 20px 'Noto Sans';color:#1E2553;background:#EEF0FA;border-radius:999px;padding:8px 18px;\">ECC</span>\n              </div>\n            </div>\n          </div>\n        </div>\n      </div>\n      <!-- voice bar: Sanad explaining -->\n      <div dir=\"rtl\" style=\"display:flex;align-items:center;gap:16px;padding:16px 32px;background:#1E2553;\">\n        <span style=\"flex:none;width:44px;height:44px;border-radius:50%;background:#FF6B5C;display:flex;align-items:center;justify-content:center;\"><svg width=\"20\" height=\"20\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2\" stroke-linecap=\"round\"><rect x=\"9\" y=\"3\" width=\"6\" height=\"11\" rx=\"3\"></rect><path d=\"M6 11a6 6 0 0 0 12 0M12 17v3\"></path></svg></span>\n        <div style=\"display:flex;align-items:center;gap:5px;height:24px;\">\n          <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out infinite;\"></span>\n          <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .15s infinite;\"></span>\n          <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .3s infinite;\"></span>\n          <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .45s infinite;\"></span>\n          <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .6s infinite;\"></span>\n        </div>\n        <span style=\"font:500 22px 'Noto Sans Arabic';color:#D7DAF2;\">سند يشرح الآن: «تخيّل أن أليس تضع قفلاً مفتوحًا للجميع… لكنها وحدها تملك المفتاح».</span>\n        <span style=\"margin-right:auto;font:600 19px 'Noto Sans Arabic';color:#fff;background:rgba(255,255,255,.12);border-radius:999px;padding:9px 18px;white-space:nowrap;\">اسأل سند ✦</span>\n      </div>\n    </div>\n  </div>\n</section>",
  "<section data-label=\"المشكلة\" data-screen-label=\"02\" data-speaker-notes=\"لاحظ هذه النقطة: المشكلة غالبًا ليست صعوبة المحتوى، بل عدم معرفة ماذا تذاكر الآن، وإلى أي عمق، وهل فهمت بما يكفي. اسأل الطالب: أيّ هذه الأسئلة الثلاثة يواجهه أكثر؟\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:16px;margin-bottom:48px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠١ · لماذا المذاكرة صعبة؟</span>\n    <h2 style=\"font:700 62px/1.4 'Noto Sans Arabic';margin:0;max-width:1400px;\">المشكلة ليست دائمًا أن المحتوى صعب — بل أنك <span style=\"color: #E8503F; border-radius: 8px; padding: 4px 12px; box-decoration-break: clone; -webkit-box-decoration-break: clone; background-color: #FFF1EF00\">لا تعرف من أين تبدأ</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:grid;grid-template-columns:repeat(3,1fr);gap:28px;\">\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:24px;padding:44px 40px;display:flex;flex-direction:column;gap:20px;\">\n      <span style=\"width:60px;height:60px;border-radius:16px;background:#FFF1EF;display:flex;align-items:center;justify-content:center;\"><svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#FF6B5C\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M4 5h16M4 12h16M4 19h9\"></path></svg></span>\n      <span style=\"font:700 36px 'Noto Sans Arabic';\">ماذا أذاكر الآن؟</span>\n      <span style=\"font:400 26px/1.55 'Noto Sans Arabic';color:#5A5F7A;\">صفحات كثيرة ووقت قليل — من أين أبدأ وما الأهم؟</span>\n    </div>\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:24px;padding:44px 40px;display:flex;flex-direction:column;gap:20px;\">\n      <span style=\"width:60px;height:60px;border-radius:16px;background:#FFF1EF;display:flex;align-items:center;justify-content:center;\"><svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#FF6B5C\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M12 3v18M5 8l7-5 7 5M5 16l7 5 7-5\"></path></svg></span>\n      <span style=\"font:700 36px 'Noto Sans Arabic';\">إلى أي عمق؟</span>\n      <span style=\"font:400 26px/1.55 'Noto Sans Arabic';color:#5A5F7A;\">هل أحفظ التفاصيل أم يكفي أن أفهم الفكرة العامة؟</span>\n    </div>\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:24px;padding:44px 40px;display:flex;flex-direction:column;gap:20px;\">\n      <span style=\"width:60px;height:60px;border-radius:16px;background:#FFF1EF;display:flex;align-items:center;justify-content:center;\"><svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#FF6B5C\" stroke-width=\"2\" stroke-linecap=\"round\"><circle cx=\"12\" cy=\"12\" r=\"9\"></circle><path d=\"M9.2 9.3a2.8 2.8 0 0 1 5.3 1c0 1.9-2.8 2.5-2.8 2.5\"></path><path d=\"M12 17.2h.01\"></path></svg></span>\n      <span style=\"font:700 36px 'Noto Sans Arabic';\">هل فهمت فعلاً؟</span>\n      <span style=\"font:400 26px/1.55 'Noto Sans Arabic';color:#5A5F7A;\">أُنهي الفصل دون أن أعرف إن كنت مستعدًا للاختبار.</span>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:40px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٢ / ١٠</span></div>\n</section>",
  "<section data-label=\"ما هو سند\" data-screen-label=\"03\" data-speaker-notes=\"التعريف الأساسي: سند يحوّل مادتك الدراسية إلى جلسة تدريس تفاعلية. أشر إلى الأفعال الأربعة — يخطّط، يشرح، يسأل، يتابع. وأكّد: سند يجلس بجانبك، لا في صندوق بحث.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:16px;margin-bottom:40px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٢ · ما هو سند؟</span>\n    <h2 style=\"font:700 60px/1.18 'Noto Sans Arabic';margin:0;max-width:1440px;\">سند يحوّل مادتك الدراسية إلى <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">جلسة تدريس تفاعلية</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;gap:54px;align-items:stretch;\">\n    <div style=\"flex:1.1;display:flex;flex-direction:column;justify-content:center;gap:22px;\">\n      <span style=\"font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\">أربعة أدوار في مدرّس واحد</span>\n      <div style=\"display:flex;flex-direction:column;gap:14px;\">\n        <div style=\"display:flex;align-items:center;gap:20px;background:#fff;border:1.5px solid #E7E1D6;border-radius:18px;padding:22px 28px;\"><span style=\"flex:none;font:700 34px 'Noto Sans';color:#FF6B5C;width:44px;\">١</span><span style=\"font:700 32px 'Noto Sans Arabic';\">يخطّط</span><span style=\"font:400 24px 'Noto Sans Arabic';color:#5A5F7A;margin-right:auto;\">ماذا تذاكر ومتى</span></div>\n        <div style=\"display:flex;align-items:center;gap:20px;background:#fff;border:1.5px solid #E7E1D6;border-radius:18px;padding:22px 28px;\"><span style=\"flex:none;font:700 34px 'Noto Sans';color:#FF6B5C;width:44px;\">٢</span><span style=\"font:700 32px 'Noto Sans Arabic';\">يشرح</span><span style=\"font:400 24px 'Noto Sans Arabic';color:#5A5F7A;margin-right:auto;\">على مادتك أنت بالذات</span></div>\n        <div style=\"display:flex;align-items:center;gap:20px;background:#fff;border:1.5px solid #E7E1D6;border-radius:18px;padding:22px 28px;\"><span style=\"flex:none;font:700 34px 'Noto Sans';color:#FF6B5C;width:44px;\">٣</span><span style=\"font:700 32px 'Noto Sans Arabic';\">يسأل</span><span style=\"font:400 24px 'Noto Sans Arabic';color:#5A5F7A;margin-right:auto;\">ليتأكد أنك فهمت</span></div>\n        <div style=\"display:flex;align-items:center;gap:20px;background:#fff;border:1.5px solid #E7E1D6;border-radius:18px;padding:22px 28px;\"><span style=\"flex:none;font:700 34px 'Noto Sans';color:#FF6B5C;width:44px;\">٤</span><span style=\"font:700 32px 'Noto Sans Arabic';\">يتابع</span><span style=\"font:400 24px 'Noto Sans Arabic';color:#5A5F7A;margin-right:auto;\">تقدّمك خطوة بخطوة</span></div>\n      </div>\n    </div>\n    <div style=\"flex:1;background:#1E2553;border-radius:28px;padding:52px 48px;display:flex;flex-direction:column;justify-content:center;gap:30px;color:#fff;position:relative;overflow:hidden;\">\n      <span style=\"position:absolute;top:-80px;left:-80px;width:280px;height:280px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,92,.25),transparent 70%);\"></span>\n      <span style=\"font:600 22px 'Noto Sans Arabic';color:#A8AEE0;position:relative;\">سند ليس…</span>\n      <div style=\"display:flex;flex-direction:column;gap:16px;position:relative;\">\n        <div style=\"display:flex;align-items:center;gap:14px;font:500 28px 'Noto Sans Arabic';color:#D7DAF2;\"><span style=\"color:#FF8E82;font:700 26px 'Noto Sans';\">✕</span> مجرّد روبوت محادثة</div>\n        <div style=\"display:flex;align-items:center;gap:14px;font:500 28px 'Noto Sans Arabic';color:#D7DAF2;\"><span style=\"color:#FF8E82;font:700 26px 'Noto Sans';\">✕</span> قارئ شرائح آلي</div>\n        <div style=\"display:flex;align-items:center;gap:14px;font:500 28px 'Noto Sans Arabic';color:#D7DAF2;\"><span style=\"color:#FF8E82;font:700 26px 'Noto Sans';\">✕</span> فيديو مسجّل لا يراك</div>\n      </div>\n      <div style=\"height:1px;background:rgba(168,174,224,.25);position:relative;\"></div>\n      <div style=\"position:relative;display:flex;align-items:center;gap:14px;background:rgba(255,107,92,.16);border:1px solid rgba(255,107,92,.4);border-radius:16px;padding:20px 24px;\">\n        <span style=\"font:700 30px 'Noto Sans Arabic';color:#fff;\">بل مدرّس يجلس بجانبك</span>\n      </div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:34px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٣ / ١٠</span></div>\n</section>",
  "<section data-label=\"جلسة سند\" data-screen-label=\"04\" data-speaker-notes=\"هذه هي التجربة الأساسية. أشر إلى الشريحة على اليسار: سند يشرح، ثم يُبرز العبارة المهمة (لاحظ التظليل)، ثم يسألك، ثم يكمل. اربط كل خطوة برقمها على اليمين.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:80px 110px 60px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:14px;margin-bottom:30px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٣ · كيف تجري الجلسة؟</span>\n    <h2 style=\"font:700 58px/1.1 'Noto Sans Arabic';margin:0;\">سند يشرح الشريحة، <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">يُشير إلى المهم</span>، ثم يسألك.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;gap:56px;align-items:center;\">\n    <!-- session mockup -->\n    <div style=\"flex:1.25;position:relative;border-radius:28px;background:#0e1430;padding:20px;box-shadow:0 40px 80px rgba(14,20,48,.38),inset 0 0 0 2px rgba(255,255,255,.05);\">\n      <div style=\"position:absolute;top:11px;left:50%;transform:translateX(-50%);width:8px;height:8px;border-radius:50%;background:#3a4a78;\"></div>\n      <div style=\"width:100%;border-radius:18px;overflow:hidden;background:#fff;display:flex;flex-direction:column;\">\n        <!-- slide viewer header -->\n        <div style=\"display:flex;align-items:center;justify-content:space-between;padding:18px 24px;background:#F4EFE6;border-bottom:1px solid #E7E1D6;\">\n          <span style=\"font:600 20px 'Noto Sans Arabic';color:#5A5F7A;\">الكيمياء العضوية · الفصل ٤</span>\n          <span style=\"font:700 16px 'Noto Sans Arabic';color:#fff;background:#FF6B5C;border-radius:999px;padding:6px 14px;\">🔥 ١٢ يومًا</span>\n        </div>\n        <!-- slide body with highlight -->\n        <div style=\"padding:30px 32px;display:flex;flex-direction:column;gap:18px;background:#fff;\">\n          <span style=\"font:700 32px 'Noto Sans Arabic';color:#1E2553;\">أنواع التفاعلات</span>\n          <div style=\"display:flex;align-items:center;gap:12px;font:500 23px 'Noto Sans Arabic';color:#5A5F7A;\"><span style=\"width:8px;height:8px;border-radius:50%;background:#A8AEE0;\"></span> تفاعلات الإضافة</div>\n          <div style=\"display:flex;align-items:center;gap:12px;position:relative;\">\n            <span style=\"width:8px;height:8px;border-radius:50%;background:#FF6B5C;\"></span>\n            <span style=\"font:700 24px 'Noto Sans Arabic';color:#1E2553;background:#FFE3DE;border-radius:8px;padding:6px 12px;box-shadow:0 0 0 2px #FF6B5C;\">تفاعلات الاستبدال — ركّز هنا</span>\n            <span style=\"font:600 17px 'Noto Sans Arabic';color:#E8503F;\">← سند يُشير</span>\n          </div>\n          <div style=\"display:flex;align-items:center;gap:12px;font:500 23px 'Noto Sans Arabic';color:#5A5F7A;\"><span style=\"width:8px;height:8px;border-radius:50%;background:#A8AEE0;\"></span> تفاعلات الحذف</div>\n        </div>\n        <!-- voice bar -->\n        <div style=\"display:flex;align-items:center;gap:16px;padding:18px 24px;background:#1E2553;\">\n          <span style=\"flex:none;width:48px;height:48px;border-radius:50%;background:#FF6B5C;display:flex;align-items:center;justify-content:center;\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2\" stroke-linecap=\"round\"><rect x=\"9\" y=\"3\" width=\"6\" height=\"11\" rx=\"3\"></rect><path d=\"M6 11a6 6 0 0 0 12 0M12 17v3\"></path></svg></span>\n          <div style=\"display:flex;align-items:center;gap:5px;height:26px;\">\n            <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out infinite;\"></span>\n            <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .15s infinite;\"></span>\n            <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .3s infinite;\"></span>\n            <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .45s infinite;\"></span>\n            <span style=\"width:4px;height:100%;background:#FF8E82;border-radius:3px;animation:sanadWave 1s ease-in-out .6s infinite;\"></span>\n          </div>\n          <span style=\"font:500 20px 'Noto Sans Arabic';color:#D7DAF2;\">سند يشرح الآن…</span>\n          <span style=\"margin-right:auto;font:600 18px 'Noto Sans Arabic';color:#fff;background:rgba(255,255,255,.12);border-radius:999px;padding:9px 18px;\">اسأل سند ✦</span>\n        </div>\n      </div>\n    </div>\n    <!-- steps -->\n    <div style=\"flex:1;display:flex;flex-direction:column;gap:8px;\">\n      <div style=\"display:flex;gap:22px;align-items:flex-start;padding:20px 0;border-bottom:1px solid #E7E1D6;\"><span style=\"flex:none;font:700 40px 'Noto Sans';color:#FF6B5C;width:52px;\">١</span><div><div style=\"font:700 30px 'Noto Sans Arabic';\">يشرح الشريحة</div><div style=\"font:400 23px/1.4 'Noto Sans Arabic';color:#5A5F7A;margin-top:4px;\">بصوت واضح، على المحتوى الذي أمامك.</div></div></div>\n      <div style=\"display:flex;gap:22px;align-items:flex-start;padding:20px 0;border-bottom:1px solid #E7E1D6;\"><span style=\"flex:none;font:700 40px 'Noto Sans';color:#FF6B5C;width:52px;\">٢</span><div><div style=\"font:700 30px 'Noto Sans Arabic';\">يُبرز النقاط المهمة</div><div style=\"font:400 23px/1.4 'Noto Sans Arabic';color:#5A5F7A;margin-top:4px;\">يظلّل العبارة ويقول: «لاحظ هذه النقطة».</div></div></div>\n      <div style=\"display:flex;gap:22px;align-items:flex-start;padding:20px 0;border-bottom:1px solid #E7E1D6;\"><span style=\"flex:none;font:700 40px 'Noto Sans';color:#FF6B5C;width:52px;\">٣</span><div><div style=\"font:700 30px 'Noto Sans Arabic';\">يسألك سؤالاً</div><div style=\"font:400 23px/1.4 'Noto Sans Arabic';color:#5A5F7A;margin-top:4px;\">وتستطيع أنت أن تسأله في أي لحظة.</div></div></div>\n      <div style=\"display:flex;gap:22px;align-items:flex-start;padding:20px 0;\"><span style=\"flex:none;font:700 40px 'Noto Sans';color:#FF6B5C;width:52px;\">٤</span><div><div style=\"font:700 30px 'Noto Sans Arabic';\">يتابع ويكمل</div><div style=\"font:400 23px/1.4 'Noto Sans Arabic';color:#5A5F7A;margin-top:4px;\">يحدّث تقدّمك وينتقل للقسم التالي.</div></div></div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:22px;border-top:1px solid #E7E1D6;margin-top:22px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٤ / ١٠</span></div>\n</section>",
  "<section data-label=\"لماذا مختلف\" data-screen-label=\"05\" data-speaker-notes=\"قارن بهدوء: الفيديوهات تشرح لكن لا تتكيّف. أدوات الذكاء العامة تجيب لكنها غير منظّمة حول مقرّرك. المدرّس الخصوصي ممتاز لكنه مكلف وغير متاح دائمًا. سند يجمع نقاط قوتها حول مقرّرك وخطتك وتقدّمك.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:14px;margin-bottom:40px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٤ · لماذا سند مختلف؟</span>\n    <h2 style=\"font:700 58px/1.1 'Noto Sans Arabic';margin:0;\">لكل بديل نقطة قوة واحدة — <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">سند يجمعها كلها</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:grid;grid-template-columns:repeat(4,1fr);gap:24px;\">\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:22px;padding:36px 32px;display:flex;flex-direction:column;gap:16px;\">\n      <span style=\"font:700 30px 'Noto Sans Arabic';color:#8B8FA8;\">الفيديوهات</span>\n      <div style=\"height:1px;background:#F0EBE1;\"></div>\n      <div style=\"font:500 23px/1.5 'Noto Sans Arabic';color:#1E2553;\">تشرح جيدًا…</div>\n      <div style=\"font:400 22px/1.5 'Noto Sans Arabic';color:#C0556A;margin-top:auto;\">لكنها لا تتكيّف معك ولا تسألك.</div>\n    </div>\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:22px;padding:36px 32px;display:flex;flex-direction:column;gap:16px;\">\n      <span style=\"font:700 30px 'Noto Sans';color:#8B8FA8;\">ChatGPT</span>\n      <div style=\"height:1px;background:#F0EBE1;\"></div>\n      <div style=\"font:500 23px/1.5 'Noto Sans Arabic';color:#1E2553;\">يجيب عن أي سؤال…</div>\n      <div style=\"font:400 22px/1.5 'Noto Sans Arabic';color:#C0556A;margin-top:auto;\">لكنه غير منظّم حول مقرّرك وخطتك.</div>\n    </div>\n    <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:22px;padding:36px 32px;display:flex;flex-direction:column;gap:16px;\">\n      <span style=\"font:700 30px 'Noto Sans Arabic';color:#8B8FA8;\">المدرّس الخصوصي</span>\n      <div style=\"height:1px;background:#F0EBE1;\"></div>\n      <div style=\"font:500 23px/1.5 'Noto Sans Arabic';color:#1E2553;\">ممتاز ويتابعك…</div>\n      <div style=\"font:400 22px/1.5 'Noto Sans Arabic';color:#C0556A;margin-top:auto;\">لكنه مكلف وغير متاح دائمًا.</div>\n    </div>\n    <div style=\"background:#1E2553;border-radius:22px;padding:36px 32px;display:flex;flex-direction:column;gap:16px;color:#fff;position:relative;box-shadow:0 30px 60px rgba(30,37,83,.24);\">\n      <span style=\"position:absolute;top:-14px;right:28px;font:700 15px 'Noto Sans Arabic';background:#FF6B5C;color:#fff;border-radius:999px;padding:6px 16px;\">سند</span>\n      <span style=\"font:700 30px 'Noto Sans Arabic';color:#fff;\">سند</span>\n      <div style=\"height:1px;background:rgba(168,174,224,.3);\"></div>\n      <div style=\"font:500 23px/1.5 'Noto Sans Arabic';color:#D7DAF2;\">يشرح، يتكيّف، ويسأل…</div>\n      <div style=\"font:600 22px/1.5 'Noto Sans Arabic';color:#FF8E82;margin-top:auto;\">منظّم حول مقرّرك وخطتك وتقدّمك.</div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:36px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٥ / ١٠</span></div>\n</section>",
  "<section data-label=\"يتكيّف معك\" data-screen-label=\"06\" data-speaker-notes=\"اشرح المرونة: إن كنت مستعجلاً قبل الاختبار، اختر المراجعة السريعة. وإن كان لديك وقت، اختر الشرح المتعمّق. سند يغيّر وتيرته وعمقه حسب حالتك وهدفك.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:14px;margin-bottom:40px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٥ · التخصيص</span>\n    <h2 style=\"font:700 58px/1.1 'Noto Sans Arabic';margin:0;\">يتكيّف مع <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">وقتك وهدفك</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;gap:32px;align-items:stretch;\">\n    <div style=\"flex:1;background:#fff;border:1.5px solid #E7E1D6;border-radius:26px;padding:48px 44px;display:flex;flex-direction:column;gap:22px;\">\n      <div style=\"display:flex;align-items:center;gap:16px;\">\n        <span style=\"width:58px;height:58px;border-radius:16px;background:#F4EFE6;display:flex;align-items:center;justify-content:center;\"><svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#1E2553\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><circle cx=\"12\" cy=\"12\" r=\"9\"></circle><path d=\"M12 7v5l3 2\"></path></svg></span>\n        <span style=\"font:700 40px 'Noto Sans Arabic';\">مراجعة سريعة</span>\n      </div>\n      <span style=\"font:400 26px/1.55 'Noto Sans Arabic';color:#5A5F7A;\">مستعجل قبل الاختبار؟ سند يركّز على الأهم فقط ويمرّ بسرعة على الأساسيات.</span>\n      <div style=\"display:flex;gap:10px;flex-wrap:wrap;margin-top:6px;\">\n        <span style=\"font:600 20px 'Noto Sans Arabic';color:#5A5F7A;background:#F4EFE6;border-radius:999px;padding:9px 18px;\">الخلاصات</span>\n        <span style=\"font:600 20px 'Noto Sans Arabic';color:#5A5F7A;background:#F4EFE6;border-radius:999px;padding:9px 18px;\">النقاط الأكثر تكرارًا</span>\n      </div>\n      <div style=\"margin-top:auto;display:flex;align-items:center;gap:12px;\"><span style=\"font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\">الوتيرة</span><div style=\"flex:1;height:10px;background:#F0EBE1;border-radius:6px;overflow:hidden;\"><div style=\"width:90%;height:100%;background:#A8AEE0;border-radius:6px;\"></div></div><span style=\"font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\">سريعة</span></div>\n    </div>\n    <div style=\"flex:1;background:#1E2553;border-radius:26px;padding:48px 44px;display:flex;flex-direction:column;gap:22px;color:#fff;position:relative;box-shadow:0 30px 60px rgba(30,37,83,.22);\">\n      <span style=\"position:absolute;top:-14px;right:44px;font:700 15px 'Noto Sans Arabic';background:#FF6B5C;color:#fff;border-radius:999px;padding:6px 16px;\">مُختار الآن</span>\n      <div style=\"display:flex;align-items:center;gap:16px;\">\n        <span style=\"width:58px;height:58px;border-radius:16px;background:rgba(255,107,92,.18);display:flex;align-items:center;justify-content:center;\"><svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#FF8E82\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 19V5M4 6h13l-2.5 3.5L17 13H4\"></path></svg></span>\n        <span style=\"font:700 40px 'Noto Sans Arabic';\">شرح متعمّق</span>\n      </div>\n      <span style=\"font:400 26px/1.55 'Noto Sans Arabic';color:#D7DAF2;\">لديك وقت؟ سند يشرح خطوة بخطوة، بالأمثلة، ويتوقّف ليتأكد أنك فهمت كل فكرة.</span>\n      <div style=\"display:flex;gap:10px;flex-wrap:wrap;margin-top:6px;\">\n        <span style=\"font:600 20px 'Noto Sans Arabic';color:#D7DAF2;background:rgba(255,255,255,.1);border-radius:999px;padding:9px 18px;\">أمثلة مفصّلة</span>\n        <span style=\"font:600 20px 'Noto Sans Arabic';color:#D7DAF2;background:rgba(255,255,255,.1);border-radius:999px;padding:9px 18px;\">أسئلة فهم</span>\n      </div>\n      <div style=\"margin-top:auto;display:flex;align-items:center;gap:12px;\"><span style=\"font:600 20px 'Noto Sans Arabic';color:#A8AEE0;\">الوتيرة</span><div style=\"flex:1;height:10px;background:rgba(255,255,255,.14);border-radius:6px;overflow:hidden;\"><div style=\"width:42%;height:100%;background:#FF6B5C;border-radius:6px;\"></div></div><span style=\"font:600 20px 'Noto Sans Arabic';color:#A8AEE0;\">متأنّية</span></div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:36px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٦ / ١٠</span></div>\n</section>",
  "<section data-label=\"مهام يومية\" data-screen-label=\"07\" data-speaker-notes=\"سند لا يترك التخطيط عليك. يقسّم المقرّر إلى مهام يومية صغيرة حول موعد اختبارك. أشر إلى المهام المكتملة، والاختبار بعد ١٨ يومًا.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:14px;margin-bottom:36px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٦ · خطة المذاكرة</span>\n    <h2 style=\"font:700 58px/1.1 'Noto Sans Arabic';margin:0;\">يقسّم المذاكرة إلى <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">مهام يومية</span> حول موعد اختبارك.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;gap:32px;align-items:stretch;\">\n    <div style=\"flex:1.3;background:#fff;border:1.5px solid #E7E1D6;border-radius:24px;padding:40px 44px;display:flex;flex-direction:column;gap:20px;\">\n      <div style=\"display:flex;align-items:center;justify-content:space-between;\">\n        <span style=\"font:700 32px 'Noto Sans Arabic';\">مهام اليوم</span>\n        <span style=\"font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\">٣ من ٥ مكتملة</span>\n      </div>\n      <div style=\"display:flex;align-items:center;gap:16px;padding:18px 22px;background:#FBF7F1;border-radius:16px;\"><span style=\"flex:none;width:30px;height:30px;border-radius:9px;background:#1E9E6A;display:flex;align-items:center;justify-content:center;\"><svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 12l5 5L20 6\"></path></svg></span><span style=\"font:500 25px 'Noto Sans Arabic';color:#8B8FA8;text-decoration:line-through;\">مراجعة ملخّص الفصل ٣</span></div>\n      <div style=\"display:flex;align-items:center;gap:16px;padding:18px 22px;background:#FBF7F1;border-radius:16px;\"><span style=\"flex:none;width:30px;height:30px;border-radius:9px;background:#1E9E6A;display:flex;align-items:center;justify-content:center;\"><svg width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 12l5 5L20 6\"></path></svg></span><span style=\"font:500 25px 'Noto Sans Arabic';color:#8B8FA8;text-decoration:line-through;\">جلسة صوتية · ٢٠ دقيقة</span></div>\n      <div style=\"display:flex;align-items:center;gap:16px;padding:18px 22px;background:#FFF1EF;border:1.5px solid #FFD9D3;border-radius:16px;\"><span style=\"flex:none;width:30px;height:30px;border-radius:9px;border:2.5px solid #FF6B5C;\"></span><span style=\"font:700 25px 'Noto Sans Arabic';color:#1E2553;\">اختبار قصير · أنواع التفاعلات</span><span style=\"margin-right:auto;font:600 17px 'Noto Sans Arabic';color:#E8503F;\">التالي</span></div>\n      <div style=\"display:flex;align-items:center;gap:16px;padding:18px 22px;background:#FBF7F1;border-radius:16px;\"><span style=\"flex:none;width:30px;height:30px;border-radius:9px;border:2.5px solid #D8D2C6;\"></span><span style=\"font:500 25px 'Noto Sans Arabic';color:#5A5F7A;\">فحص استيعاب · الفصل ٤</span></div>\n    </div>\n    <div style=\"flex:1;display:flex;flex-direction:column;gap:24px;\">\n      <div style=\"flex:1;background:#1E2553;border-radius:24px;padding:36px 38px;display:flex;flex-direction:column;justify-content:center;gap:10px;color:#fff;\">\n        <span style=\"font:600 22px 'Noto Sans Arabic';color:#A8AEE0;\">الاختبار القادم</span>\n        <span style=\"font:700 96px/1 'Noto Sans';color:#FF6B5C;\">١٨<span style=\"font:600 30px 'Noto Sans Arabic';color:#D7DAF2;\"> يومًا</span></span>\n        <span style=\"font:500 23px 'Noto Sans Arabic';color:#D7DAF2;\">الكيمياء العضوية · ١٨ مايو</span>\n        <div style=\"display:flex;gap:6px;margin-top:14px;\"><span style=\"flex:1;height:8px;border-radius:4px;background:#FF6B5C;\"></span><span style=\"flex:1;height:8px;border-radius:4px;background:#4C57C7;\"></span><span style=\"flex:1;height:8px;border-radius:4px;background:#A8AEE0;\"></span><span style=\"flex:1;height:8px;border-radius:4px;background:rgba(255,255,255,.18);\"></span></div>\n      </div>\n      <div style=\"flex:none;background:#fff;border:1.5px solid #E7E1D6;border-radius:24px;padding:30px 38px;display:flex;align-items:center;gap:18px;\">\n        <span style=\"width:52px;height:52px;border-radius:14px;background:#FFF1EF;display:flex;align-items:center;justify-content:center;\"><svg width=\"28\" height=\"28\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#FF6B5C\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><rect x=\"3\" y=\"4\" width=\"18\" height=\"17\" rx=\"3\"></rect><path d=\"M3 9h18M8 2v4M16 2v4\"></path></svg></span>\n        <span style=\"font:500 25px/1.4 'Noto Sans Arabic';color:#3A3F5A;\">خطة موزّعة على أيامك — <span style=\"color:#1E2553;font-weight:700;\">دون ضغط اللحظة الأخيرة</span>.</span>\n      </div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:30px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٧ / ١٠</span></div>\n</section>",
  "<section data-label=\"سؤال سريع\" data-screen-label=\"08\" data-speaker-notes=\"لحظة إثبات مهمة: توقّف واسأل الطالب هذا السؤال فعليًا. انتظر إجابته ثم أظهر أن الخيار الثاني هو الصحيح. أكّد: هكذا يتأكد سند أنك فهمت قبل أن نكمل.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:radial-gradient(120% 130% at 15% 0%,#27326B,#1E2553 58%,#161D44);color:#fff;padding:88px 110px;display:flex;flex-direction:column;justify-content:center;gap:40px;position:relative;overflow:hidden;\">\n  <span style=\"position:absolute;top:-120px;left:-100px;width:460px;height:460px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,92,.22),transparent 70%);\"></span>\n  <div style=\"display:flex;flex-direction:column;gap:20px;position:relative;\">\n    <span style=\"display:inline-flex;align-self:flex-start;align-items:center;gap:10px;background:#FF6B5C;color:#fff;border-radius:999px;padding:11px 24px;font:700 22px 'Noto Sans Arabic';\"><svg width=\"22\" height=\"22\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"2.4\" stroke-linecap=\"round\"><path d=\"M9.2 9.3a2.8 2.8 0 0 1 5.3 1c0 1.9-2.8 2.5-2.8 2.5\"></path><path d=\"M12 17.2h.01\"></path></svg> سؤال سريع</span>\n    <h2 style=\"font:700 62px/1.2 'Noto Sans Arabic';margin:0;max-width:1500px;\">ما الذي يميّز سند عن أداة ذكاء اصطناعي عامة؟</h2>\n  </div>\n  <div style=\"display:grid;grid-template-columns:repeat(3,1fr);gap:24px;position:relative;\">\n    <div style=\"background:rgba(255,255,255,.06);border:1.5px solid rgba(168,174,224,.28);border-radius:20px;padding:32px 30px;display:flex;flex-direction:column;gap:18px;\">\n      <span style=\"width:44px;height:44px;border-radius:50%;border:2px solid #A8AEE0;display:flex;align-items:center;justify-content:center;font:700 22px 'Noto Sans Arabic';color:#A8AEE0;\">أ</span>\n      <span style=\"font:500 27px/1.45 'Noto Sans Arabic';color:#D7DAF2;\">لأنه يجيب أسرع عن الأسئلة.</span>\n    </div>\n    <div style=\"background:rgba(255,107,92,.14);border:2px solid #FF6B5C;border-radius:20px;padding:32px 30px;display:flex;flex-direction:column;gap:18px;box-shadow:0 24px 50px rgba(255,107,92,.24);\">\n      <span style=\"width:44px;height:44px;border-radius:50%;background:#FF6B5C;display:flex;align-items:center;justify-content:center;\"><svg width=\"24\" height=\"24\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 12l5 5L20 6\"></path></svg></span>\n      <span style=\"font:700 27px/1.45 'Noto Sans Arabic';color:#fff;\">لأنه منظّم حول مقرّرك وخطتك وتقدّمك.</span>\n    </div>\n    <div style=\"background:rgba(255,255,255,.06);border:1.5px solid rgba(168,174,224,.28);border-radius:20px;padding:32px 30px;display:flex;flex-direction:column;gap:18px;\">\n      <span style=\"width:44px;height:44px;border-radius:50%;border:2px solid #A8AEE0;display:flex;align-items:center;justify-content:center;font:700 22px 'Noto Sans Arabic';color:#A8AEE0;\">ج</span>\n      <span style=\"font:500 27px/1.45 'Noto Sans Arabic';color:#D7DAF2;\">لأنه يستخدم صوتًا بشريًا فقط.</span>\n    </div>\n  </div>\n  <div style=\"display:flex;align-items:center;gap:14px;position:relative;font:500 24px 'Noto Sans Arabic';color:#A8AEE0;\">\n    <span style=\"width:12px;height:12px;border-radius:50%;background:#FF6B5C;\"></span>\n    هكذا يتأكد سند أنك فهمت <span style=\"color:#fff;\">قبل أن نكمل</span> — لا مجرد أن يشرح ويمضي.\n  </div>\n</section>",
  "<section data-label=\"تقدّمك\" data-screen-label=\"09\" data-speaker-notes=\"بعد كل قسم، يحدّث سند تقدّمك: يرفع النسبة، يكمل القسم، ويحافظ على استمراريتك. هذا يعطي الطالب إحساسًا واضحًا بالإنجاز.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:#FBF7F1;color:#1E2553;padding:84px 110px 64px;display:flex;flex-direction:column;\">\n  <div style=\"display:flex;flex-direction:column;gap:14px;margin-bottom:40px;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس ٠٧ · التقدّم</span>\n    <h2 style=\"font:700 58px/1.1 'Noto Sans Arabic';margin:0;\">يحدّث تقدّمك <span style=\"color:#E8503F;background:#FFF1EF;border-radius:8px;padding:0 12px;\">بعد كل قسم</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;gap:32px;align-items:stretch;\">\n    <div style=\"flex:1;background:#1E2553;border-radius:26px;padding:48px 44px;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:24px;color:#fff;\">\n      <div style=\"position:relative;width:260px;height:260px;border-radius:50%;background:conic-gradient(#FF6B5C 0 68%,rgba(255,255,255,.12) 68% 100%);display:flex;align-items:center;justify-content:center;\">\n        <div style=\"width:196px;height:196px;border-radius:50%;background:#1E2553;display:flex;flex-direction:column;align-items:center;justify-content:center;\"><span style=\"font:700 76px/1 'Noto Sans';color:#fff;\">٦٨٪</span><span style=\"font:500 22px 'Noto Sans Arabic';color:#A8AEE0;margin-top:6px;\">من الفصل ٤</span></div>\n      </div>\n      <span style=\"font:600 26px 'Noto Sans Arabic';color:#D7DAF2;\">أنجزت ٣ أقسام من ٥</span>\n    </div>\n    <div style=\"flex:1.25;display:flex;flex-direction:column;gap:20px;\">\n      <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:20px;padding:28px 32px;display:flex;flex-direction:column;gap:12px;\">\n        <div style=\"display:flex;justify-content:space-between;font:600 24px 'Noto Sans Arabic';\"><span>مقدمة التفاعلات</span><span style=\"color:#1E9E6A;\">مكتمل ✓</span></div>\n        <div style=\"height:12px;background:#F0EBE1;border-radius:6px;overflow:hidden;\"><div style=\"width:100%;height:100%;background:#1E9E6A;border-radius:6px;\"></div></div>\n      </div>\n      <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:20px;padding:28px 32px;display:flex;flex-direction:column;gap:12px;\">\n        <div style=\"display:flex;justify-content:space-between;font:600 24px 'Noto Sans Arabic';\"><span>تفاعلات الاستبدال</span><span style=\"color:#E8503F;\">قيد التقدّم</span></div>\n        <div style=\"height:12px;background:#F0EBE1;border-radius:6px;overflow:hidden;\"><div style=\"width:60%;height:100%;background:#FF6B5C;border-radius:6px;\"></div></div>\n      </div>\n      <div style=\"background:#fff;border:1.5px solid #E7E1D6;border-radius:20px;padding:28px 32px;display:flex;flex-direction:column;gap:12px;opacity:.7;\">\n        <div style=\"display:flex;justify-content:space-between;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span>تفاعلات الحذف</span><span>لم يبدأ</span></div>\n        <div style=\"height:12px;background:#F0EBE1;border-radius:6px;overflow:hidden;\"><div style=\"width:0%;height:100%;background:#A8AEE0;border-radius:6px;\"></div></div>\n      </div>\n      <div style=\"margin-top:auto;background:#FFF1EF;border:1.5px solid #FFD9D3;border-radius:20px;padding:26px 32px;display:flex;align-items:center;gap:16px;\">\n        <span style=\"width:52px;height:52px;border-radius:14px;background:#FF6B5C;display:flex;align-items:center;justify-content:center;\"><svg width=\"26\" height=\"26\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"#fff\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M4 12l5 5L20 6\"></path></svg></span>\n        <span style=\"font:700 28px 'Noto Sans Arabic';color:#1E2553;\">أحسنت! أنهيت هذا القسم.</span>\n      </div>\n    </div>\n  </div>\n  <div style=\"display:flex;justify-content:space-between;align-items:center;padding-top:26px;border-top:1px solid #E7E1D6;margin-top:30px;font:600 24px 'Noto Sans Arabic';color:#8B8FA8;\"><span style=\"display:flex;align-items:center;gap:9px;\"><span style=\"width:12px;height:12px;background:#FF6B5C;border-radius:50%;\"></span>سند · دورة تعريفية</span><span style=\"font:600 24px 'Noto Sans';\">٠٩ / ١٠</span></div>\n</section>",
  "<section data-label=\"ابدأ الآن\" data-screen-label=\"10\" data-speaker-notes=\"أغلق التجربة: كل ما رأيته الآن كان على مقرّر تجريبي. تخيّله على مقرّرك أنت. ارفع شرائحك أو ملف PDF، وسيبدأ سند جلستك الأولى فورًا.\" dir=\"rtl\" style=\"min-height:100%;font-family:'Noto Sans Arabic','Noto Sans',sans-serif;background:radial-gradient(120% 130% at 85% 100%,#27326B,#1E2553 55%,#161D44);color:#fff;padding:96px 110px;display:flex;align-items:center;gap:72px;position:relative;overflow:hidden;\">\n  <span style=\"position:absolute;top:-140px;right:-120px;width:520px;height:520px;border-radius:50%;background:radial-gradient(circle,rgba(255,107,92,.26),transparent 68%);\"></span>\n  <div style=\"flex:1.2;display:flex;flex-direction:column;gap:30px;position:relative;z-index:1;\">\n    <span style=\"font:700 24px 'Noto Sans Arabic';letter-spacing:.06em;color:#FF6B5C;\">الدرس الأخير · ابدأ رحلتك</span>\n    <h2 style=\"font:700 100px/1.05 'Noto Sans Arabic';margin:0;\">تخيّل هذا…<br><span style=\"color:#FF6B5C;\">مع مقرّرك أنت</span>.</h2>\n  </div>\n  <div style=\"flex:1;display:flex;justify-content:center;align-items:center;position:relative;z-index:1;\">\n    <div style=\"display:flex;flex-direction:column;align-items:center;\">\n      <span style=\"font:700 120px/1 'Bricolage Grotesque',sans-serif;color:#fff;letter-spacing:-.03em;\">sanad</span>\n      <span style=\"width:220px;height:14px;border-radius:7px;background:#FF6B5C;margin-top:26px;\"></span>\n    </div>\n  </div>\n</section>",
];

const DESIGN_WIDTH = 1920;
const DESIGN_HEIGHT = 1080;

function applyMarker(
  root: HTMLElement,
  id: string,
  payload: markerPayload,
): boolean {
  if (root.querySelector("mark#" + CSS.escape(id))) return true;
  const slide = root.children[payload.page - 1] as Element | undefined;
  if (!slide) return false;
  const walker = document.createTreeWalker(slide, NodeFilter.SHOW_TEXT, {
    acceptNode(node) {
      const parent = (node as Text).parentElement;
      if (
        parent?.closest(
          "mark.agent-highlight, mark.agent-circle, mark.agent-underline, mark.agent-point",
        )
      ) {
        return NodeFilter.FILTER_REJECT;
      }
      return NodeFilter.FILTER_ACCEPT;
    },
  });
  let node = walker.nextNode() as Text | null;
  while (node) {
    const value = node.nodeValue ?? "";
    const idx = value.indexOf(payload.text);
    if (idx !== -1) {
      const range = document.createRange();
      range.setStart(node, idx);
      range.setEnd(node, idx + payload.text.length);
      const mark = document.createElement("mark");
      mark.id = id;
      mark.className = `agent-${payload.type}`;
      try {
        range.surroundContents(mark);
      } catch {
        return false;
      }
      return true;
    }
    node = walker.nextNode() as Text | null;
  }
  return false;
}

function clearMarker(root: HTMLElement, id: string): void {
  const mark = root.querySelector("mark#" + CSS.escape(id));
  if (!mark) return;
  const parent = mark.parentNode;
  if (!parent) return;
  while (mark.firstChild) parent.insertBefore(mark.firstChild, mark);
  parent.removeChild(mark);
  parent.normalize();
}

export const PdfCanvas = memo(function PdfCanvas({
  api,
  setApi,
  numPages,
  setNumPages,
  activeMarker,
}: {
  pdfUrl: string | null;
  api: CarouselApi | null;
  setApi: React.Dispatch<React.SetStateAction<CarouselApi | null>>;
  numPages: number;
  setNumPages: React.Dispatch<React.SetStateAction<number>>;
  activeMarker: Record<string, markerPayload>;
}) {
  const [pageNumber, setPageNumber] = useState<number>(1);
  const [scale, setScale] = useState<number>(1);
  const [containerSize, setContainerSize] = useState<{
    width: number;
    height: number;
  }>({ width: 0, height: 0 });
  const stageRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setNumPages(SLIDES.length);
  }, [setNumPages]);

  useEffect(() => {
    const el = stageRef.current;
    if (!el) return;
    const measure = () =>
      setContainerSize({ width: el.clientWidth, height: el.clientHeight });
    measure();
    const observer = new ResizeObserver(measure);
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  useEffect(() => {
    if (!api) {
      return;
    }
    setPageNumber(api.selectedScrollSnap() + 1);
    api.on("select", () => {
      setPageNumber(api.selectedScrollSnap() + 1);
    });
  }, [api]);

  const appliedRef = useRef<Record<string, markerPayload>>({});

  useEffect(() => {
    if (!api) return;
    const root = api.containerNode();
    if (!root) return;
    const prev = appliedRef.current;
    for (const key of Object.keys(prev)) {
      if (!(key in activeMarker)) {
        clearMarker(root, key);
        delete prev[key];
      }
    }
    for (const key of Object.keys(activeMarker)) {
      const payload = activeMarker[key];
      const stored = prev[key];
      const markerChanged =
        !!stored &&
        (stored.type !== payload.type ||
          stored.page !== payload.page ||
          stored.text !== payload.text);
      if (markerChanged) clearMarker(root, key);
      if (applyMarker(root, key, payload)) {
        prev[key] = payload;
      }
    }
  }, [activeMarker, api, containerSize]);

  const fitScale =
    containerSize.width > 0 && containerSize.height > 0
      ? Math.min(
          containerSize.width / DESIGN_WIDTH,
          containerSize.height / DESIGN_HEIGHT,
        )
      : 0;
  const renderScale = fitScale * scale;

  return (
    <Carousel
      className="mx-auto flex h-full w-full max-w-240 flex-col overflow-hidden"
      setApi={setApi}
      dir="ltr"
    >
      <div
        ref={stageRef}
        className="relative flex min-h-0 flex-1 items-center justify-center overflow-hidden [&>[data-slot=carousel-content]]:absolute [&>[data-slot=carousel-content]]:inset-0"
      >
        <CarouselContent className="h-full">
          {SLIDES.map((html, index) => (
            <CarouselItem key={index} className="h-full">
              <div className="flex h-full w-full items-center justify-center overflow-auto">
                {renderScale > 0 && (
                  <div
                    style={{
                      width: DESIGN_WIDTH * renderScale,
                      height: DESIGN_HEIGHT * renderScale,
                      flexShrink: 0,
                    }}
                  >
                    <div
                      style={{
                        width: DESIGN_WIDTH,
                        height: DESIGN_HEIGHT,
                        transform: `scale(${renderScale})`,
                        transformOrigin: "top left",
                      }}
                      dangerouslySetInnerHTML={{ __html: html }}
                    />
                  </div>
                )}
              </div>
            </CarouselItem>
          ))}
        </CarouselContent>
      </div>
      <div className="relative z-20 flex shrink-0 items-center justify-center py-2">
        <ContentToolbar
          pageNumber={pageNumber}
          numPages={numPages}
          zoom={scale}
          setZoom={setScale}
        />
      </div>
    </Carousel>
  );
});
